fn main() {
    let s: &str = "Hello, Rust!";
    println!("{}", s);
    println!("length: {}", s.len());
}

fn main() {
    let mut s = String::from("Hello");
    s.push_str(", Rust!");
    println!("{}", s);
    println!("length: {}", s.len());
}

fn main() {
    let mut s = String::from("hel");
    s.push('l');
    s.push('o');
    s.push_str(" world");
    println!("{}", s);
}

fn main() {
    let first = "Hello";
    let second = "Rust";
    let msg = format!("{}, {}! Version {}", first, second, 2024);
    println!("{}", msg);
}

fn main() {
    let s = String::from("  hello rust  ");
    println!("{}", s.trim());
    println!("{}", s.trim().to_uppercase());
    println!("{}", s.contains("rust"));
    println!("{}", s.replace("rust", "world"));
}

fn main() {
    let csv = "one,two,three,four";
    let parts: Vec<&str> = csv.split(',').collect();
    println!("{:?}", parts);
    println!("count: {}", parts.len());
}

fn main() {
    let url = "https://rust-lang.org";
    println!("{}", url.starts_with("https"));
    println!("{}", url.ends_with(".org"));
    println!("{}", url.find("rust"));
}

fn main() {
    let n: i32 = 42;
    let s = n.to_string();
    println!("string: {}", s);
    let back: i32 = s.parse().unwrap();
    println!("number: {}", back);
}
